import{_ as l,o,c as a,a5 as t}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0030：故障码与故障日志","description":"","frontmatter":{"title":"教程 0030：故障码与故障日志","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0030-ups-fault-code-logging.html","status":"learning","visibility":"public","summary":"Imported from 0030-ups-fault-code-logging.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0030-ups-fault-code-logging.md","filePath":"content/power/lessons/0030-ups-fault-code-logging.md","lastUpdated":null}'),p={name:"content/power/lessons/0030-ups-fault-code-logging.md"};function i(d,e,r,s,c,n){return o(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="教程-0030-故障码与故障日志" tabindex="-1">教程 0030：故障码与故障日志 <a class="header-anchor" href="#教程-0030-故障码与故障日志" aria-label="Permalink to &quot;教程 0030：故障码与故障日志&quot;">​</a></h1><p>中文主讲。一个概念：故障闭环之后要留下可调试证据，记录什么故障、何时发生、由谁触发、当时处于什么模式。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学故障码和教学日志字段，不包含公司内部故障码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>故障码（fault code）是给故障原因分配的可读编号或枚举。故障日志（fault log）是在故障发生时记录一条事件，通常包含时间戳（timestamp）、故障码、触发源（trigger source）、发生时模式和是否锁存。</p><p>本节只讲一个概念：故障闭环之后要留下可调试证据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 现场问题常常不是“故障有没有发生”，而是“先发生了什么、谁触发的、当时处于什么模式”。没有故障日志，工程师只能靠用户描述、现象猜测和复现尝试。</p><p>教学日志让你建立阅读路径：故障码说明类别，时间戳说明发生时刻，触发源说明来自哪个模块，模式说明系统当时处于什么状态。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>故障锁存（fault latch）像拉下急停，故障日志像在值班记录本上写一行：什么时候、什么故障、谁报的警、当时设备处于什么运行状态。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>if latched_fault rises from 0 to 1: event.timestamp_ms = now_ms event.fault_code = detected_fault_code event.trigger_source = &quot;protection module&quot; event.mode_when_logged = current_mode event.latched_fault = 1</p><p>本课只记录单条教学事件，不实现环形缓冲区、Flash 保存或通信上传。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_fault_code_logging.py</p><p>只保存图片、不自动打开：</p><p>python simulations\\python\\ups_fault_code_logging.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_fault_code_logging.png</code></p></li><li><p>终端输出：首次记录的故障码、日志时间戳、锁存期间是否只记录一次。</p></li><li><p>图内包含参数框、图例、故障码、日志脉冲和记录时模式。</p></li></ul><p>观察顺序：先看保护故障触发锁存，再看日志脉冲只出现一次，然后看故障码变为 <code>DC_BUS_OV</code>，记录时模式为 FAULT。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsFaultCode</code>：教学故障码枚举。</p></li><li><p><code>UpsFaultLogEvent</code>：单条日志事件。</p></li><li><p><code>UpsFaultLog_Record()</code>：生成故障日志事件。</p></li><li><p><code>UpsFaultLog_Print()</code>：把事件打印成可检查证据。</p></li></ul><p>真实工程还会涉及日志缓存、掉电保存、擦写寿命、通信读取、故障码版本兼容等问题，本节先不展开。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**有故障锁存就不需要日志。 **纠正：**锁存告诉你系统停了，日志告诉你为什么停、什么时候停、谁触发。</p></li><li><p>**误解：**日志越多越好。 **纠正：**嵌入式存储有限，日志要记录关键事件和关键字段。</p></li><li><p>**误解：**导师给的真实故障码可以记进学习仓库。 **纠正：**不能记录公司内部故障码，只能记录通用组织方式和字段设计思路。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_fault_code_logging.py --no-open</code> 并打开 <code>simulations/results/ups_fault_code_logging.png</code>。</p></li><li><p>能解释故障码、时间戳、触发源、模式和锁存字段分别解决什么问题。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>fault_log</code> 输出。</p></li><li><p>能基于 <code>fault_log.c -&gt; UpsFaultLog_Record()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么故障日志不能只记录“发生故障”四个字？</p></li><li><p>为什么触发源字段对阅读 C 工程很重要？</p></li><li><p>如果同一故障反复发生，是追加日志、覆盖日志还是增加计数？这三种方式各有什么取舍？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>fault_log.c -&gt; UpsFaultLog_Record()</code> 记录时间戳、故障码、触发源和模式。真实工程里故障日志通常还会记录哪些通用字段？</p></li><li><p>我用 <code>simulations/results/ups_fault_code_logging.png</code> 看到日志只在锁存时记录一次。真实工程里同一故障重复出现时会覆盖、追加还是计数？</p></li><li><p>我不会记录公司内部故障码，只想确认组织方式：真实工程里故障码是否有版本号、分类范围或通信协议映射？</p></li></ul><p>**下一步：**可以继续补通信查询接口，让外部工具读取模式、故障码、最近日志和关键参数。</p><p>关联：<a href="./0029-ups-system-fault-closure.html">上一节：系统故障闭环</a>；源稿：<code>concepts/embedded/ups-fault-code-logging.md</code>；仿真：<code>simulations/python/ups_fault_code_logging.py</code>。</p><pre><code>上一节：教程 0029：系统故障闭环
下一节：教程 0031：UPS 遥测通信帧
</code></pre>`,38)])])}const h=l(p,[["render",i]]);export{_ as __pageData,h as default};
